class Account:
    club_name = "Riverside Club"

    def __init__(self, owner, balance):
        self.owner = owner
        self.balance = balance

    @staticmethod
    def is_valid_amount(amount):
        return amount > 0

    @classmethod
    def starter_account(cls, owner):
        return cls(owner, 25)

    def deposit(self, amount):
        if self.is_valid_amount(amount):
            self.balance += amount
        return self.balance

    def withdraw(self, amount):
        if self.is_valid_amount(amount) and amount <= self.balance:
            self.balance -= amount
        return self.balance

    def summary(self):
        return f"{self.club_name} | {self.owner}: ${self.balance:.2f}"
